1	/* Shared UI atoms for the item-detail redesign.
2	   All styling inline (CSS-var driven) so the three variation files can
3	   reuse them. Exported to window at the bottom. */
4	const { useState } = React;
5	
6	/* ---------- tiny line-icon set (functional UI glyphs only) ---------- */
7	function Icon({ name, size = 16, sw = 1.7, color = "currentColor", style }) {
8	  const p = {
9	    download:   <><path d="M12 4v10M8 12l4 4 4-4" /><path d="M5 19h14" /></>,
10	    upload:     <><path d="M12 20V10M8 12l4-4 4 4" /><path d="M5 5h14" /></>,
11	    edit:       <><path d="M14 5l5 5M4 20l1-4L16 5l3 3L8 19l-4 1z" /></>,
12	    plus:       <><path d="M12 5v14M5 12h14" /></>,
13	    check:      <><path d="M5 12l4.5 4.5L19 7" /></>,
14	    chevR:      <><path d="M9 5l7 7-7 7" /></>,
15	    chevL:      <><path d="M15 5l-7 7 7 7" /></>,
16	    chevD:      <><path d="M5 9l7 7 7-7" /></>,
17	    dot:        <circle cx="12" cy="12" r="4" fill={color} stroke="none" />,
18	    clock:      <><circle cx="12" cy="12" r="8" /><path d="M12 8v4l3 2" /></>,
19	    clip:       <><path d="M20 11l-8.5 8.5a4 4 0 01-6-6L13 5a2.6 2.6 0 014 3.5l-8 8a1.3 1.3 0 01-2-2l7.5-7.5" /></>,
20	    chat:       <><path d="M5 6h14v10H9l-4 4V6z" /></>,
21	    image:      <><rect x="4" y="5" width="16" height="14" rx="2" /><circle cx="9" cy="10" r="1.6" /><path d="M5 17l4.5-4 3 2.5L16 11l3 3.5" /></>,
22	    tag:        <><path d="M4 4h7l9 9-7 7-9-9V4z" /><circle cx="8" cy="8" r="1.4" /></>,
23	    ext:        <><path d="M14 5h5v5M19 5l-8 8M11 5H5v14h14v-6" /></>,
24	    user:       <><circle cx="12" cy="8" r="3.6" /><path d="M5 20c1.2-3.6 4-5 7-5s5.8 1.4 7 5" /></>,
25	    box:        <><path d="M4 8l8-4 8 4-8 4-8-4z" /><path d="M4 8v8l8 4 8-4V8M12 12v8" /></>,
26	    grid:       <><rect x="4" y="4" width="6" height="6" rx="1" /><rect x="14" y="4" width="6" height="6" rx="1" /><rect x="4" y="14" width="6" height="6" rx="1" /><rect x="14" y="14" width="6" height="6" rx="1" /></>,
27	    cal:        <><rect x="4" y="5" width="16" height="15" rx="2" /><path d="M4 9h16M9 3v4M15 3v4" /></>,
28	    layers:     <><path d="M12 4l8 4-8 4-8-4 8-4z" /><path d="M4 12l8 4 8-4M4 16l8 4 8-4" /></>,
29	    search:     <><circle cx="11" cy="11" r="6" /><path d="M20 20l-4-4" /></>,
30	    bell:       <><path d="M6 9a6 6 0 0112 0c0 5 2 6 2 6H4s2-1 2-6z" /><path d="M10 20a2 2 0 004 0" /></>,
31	    star:       <><path d="M12 4l2.4 5 5.6.6-4.2 3.8 1.2 5.6L12 16.2 7 19l1.2-5.6L4 9.6 9.6 9 12 4z" /></>,
32	    sparkle:    <><path d="M12 4l1.6 4.4L18 10l-4.4 1.6L12 16l-1.6-4.4L6 10l4.4-1.6L12 4z" /></>,
33	  }[name];
34	  return (
35	    <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
36	      stroke={color} strokeWidth={sw} strokeLinecap="round" strokeLinejoin="round"
37	      style={{ display: "block", flex: "none", ...style }}>{p}</svg>
38	  );
39	}
40	
41	/* ---------- text helpers ---------- */
42	function Mono({ children, style }) {
43	  return <span style={{ fontFamily: "var(--mono)", fontFeatureSettings: '"tnum" 1', ...style }}>{children}</span>;
44	}
45	
46	/* ---------- colored icon badge ---------- */
47	const ICON_TONES = {
48	  indigo: { bg: "#eceaf7", fg: "#403d8c" },
49	  violet: { bg: "#f1e7f8", fg: "#7d3ca3" },
50	  teal:   { bg: "#dff0ed", fg: "#1d7a6d" },
51	  green:  { bg: "#e6f1e9", fg: "#2e7a4d" },
52	  amber:  { bg: "#f8eed9", fg: "#9a6810" },
53	  clay:   { bg: "#f8eadf", fg: "#9c4f22" },
54	  blue:   { bg: "#e4edfc", fg: "#285aac" },
55	  rose:   { bg: "#fae6ec", fg: "#aa3957" },
56	};
57	function IconBadge({ name, tone = "indigo", size = 26, icon = 15, style }) {
58	  const t = ICON_TONES[tone] || ICON_TONES.indigo;
59	  return (
60	    <span style={{ width: size, height: size, borderRadius: 7, flex: "none", background: t.bg, color: t.fg, display: "flex", alignItems: "center", justifyContent: "center", ...style }}>
61	      <Icon name={name} size={icon} color={t.fg} />
62	    </span>
63	  );
64	}
65	
66	/* ---------- status pill ---------- */
67	const PILL_TONES = {
68	  neutral: { bg: "var(--chip)",     fg: "var(--ink-2)",  dot: "var(--ink-3)" },
69	  brand:   { bg: "var(--brand-50)", fg: "var(--brand-700)", dot: "var(--brand)" },
70	  success: { bg: "#e8f1ea",         fg: "#2f6a45",       dot: "#3f8a5b" },
71	  warning: { bg: "#f7efe0",         fg: "#8a6312",       dot: "#c08a2a" },
72	  danger:  { bg: "#f7e7e4",         fg: "#9a3a30",       dot: "#bd5246" },
73	  accent:  { bg: "var(--accent-50)",fg: "var(--accent-700)", dot: "var(--accent)" },
74	};
75	function Pill({ tone = "neutral", dot = true, children, style }) {
76	  const t = PILL_TONES[tone] || PILL_TONES.neutral;
77	  return (
78	    <span style={{
79	      display: "inline-flex", alignItems: "center", gap: 6, height: 22,
80	      padding: "0 9px", borderRadius: 999, background: t.bg, color: t.fg,
81	      fontSize: 11.5, fontWeight: 600, letterSpacing: ".01em", whiteSpace: "nowrap", ...style,
82	    }}>
83	      {dot && <span style={{ width: 6, height: 6, borderRadius: 99, background: t.dot, flex: "none" }} />}
84	      {children}
85	    </span>
86	  );
87	}
88	
89	/* ---------- read-only definition field ---------- */
90	function Field({ label, value, hint, mono, strong, accent, wide }) {
91	  const empty = value === undefined || value === null || value === "" || value === "-";
92	  return (
93	    <div style={{ display: "flex", flexDirection: "column", gap: 3, minWidth: 0, gridColumn: wide ? "1 / -1" : "auto" }}>
94	      <span style={{
95	        fontSize: 10.5, fontWeight: 600, letterSpacing: ".07em", textTransform: "uppercase",
96	        color: "var(--ink-3)", display: "inline-flex", alignItems: "center", gap: 5,
97	      }}>
98	        {label}
99	        {hint && <Mono style={{ fontSize: 9.5, color: "var(--ink-4)", fontWeight: 500, letterSpacing: 0 }}>{hint}</Mono>}
100	      </span>
101	      <span style={{
102	        fontSize: 13.5, lineHeight: 1.35,
103	        fontWeight: strong ? 600 : 500,
104	        fontFamily: mono ? "var(--mono)" : "inherit",
105	        color: empty ? "var(--ink-4)" : accent ? "var(--accent-700)" : "var(--ink)",
106	        wordBreak: "break-word",
107	      }}>{empty ? "—" : value}</span>
108	    </div>
109	  );
110	}
111	
112	function FieldGrid({ cols = 3, children, gap = 22 }) {
113	  return (
114	    <div style={{ display: "grid", gridTemplateColumns: `repeat(${cols}, minmax(0,1fr))`, gap, rowGap: gap }}>
115	      {children}
116	    </div>
117	  );
118	}
119	
120	/* ---------- card ---------- */
121	function Card({ title, kicker, action, children, pad = 18, style, bodyStyle, icon, tone = "indigo" }) {
122	  return (
123	    <section style={{
124	      background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 12,
125	      boxShadow: "0 1px 2px rgba(28,27,34,.04)", display: "flex", flexDirection: "column", minWidth: 0, ...style,
126	    }}>
127	      {(title || action) && (
128	        <header style={{
129	          display: "flex", alignItems: "center", justifyContent: "space-between",
130	          padding: "11px 16px", borderBottom: "1px solid var(--line-2)", gap: 12,
131	        }}>
132	          <div style={{ display: "flex", alignItems: "center", gap: 10, minWidth: 0 }}>
133	            {icon && <IconBadge name={icon} tone={tone} size={28} icon={15} />}
134	            <div style={{ minWidth: 0 }}>
135	              {kicker && <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: ".09em", textTransform: "uppercase", color: ICON_TONES[tone].fg }}>{kicker}</div>}
136	              <h3 style={{ margin: 0, fontSize: 13.5, fontWeight: 600, color: "var(--ink)", letterSpacing: "-.01em", whiteSpace: "nowrap" }}>{title}</h3>
137	            </div>
138	          </div>
139	          {action}
140	        </header>
141	      )}
142	      <div style={{ padding: pad, ...bodyStyle }}>{children}</div>
143	    </section>
144	  );
145	}
146	
147	function SectionLabel({ children, hint, icon, tone = "indigo" }) {
148	  return (
149	    <div style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 13 }}>
150	      {icon && <IconBadge name={icon} tone={tone} size={22} icon={13} />}
151	      <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: ".08em", textTransform: "uppercase", color: "var(--ink-2)" }}>{children}</span>
152	      <span style={{ flex: 1, height: 1, background: "var(--line-2)" }} />
153	      {hint && <Mono style={{ fontSize: 10, color: "var(--ink-4)" }}>{hint}</Mono>}
154	    </div>
155	  );
156	}
157	
158	/* ---------- buttons ---------- */
159	function Btn({ variant = "ghost", icon, children, onClick, size = "md", style }) {
160	  const h = size === "sm" ? 28 : 34;
161	  const base = {
162	    display: "inline-flex", alignItems: "center", gap: 7, height: h, padding: size === "sm" ? "0 11px" : "0 14px",
163	    borderRadius: 8, fontSize: 12.5, fontWeight: 600, cursor: "pointer", whiteSpace: "nowrap",
164	    border: "1px solid transparent", transition: "background .15s,border-color .15s,color .15s", fontFamily: "inherit",
165	  };
166	  const variants = {
167	    primary: { background: "var(--brand)", color: "#fff", borderColor: "var(--brand)" },
168	    accent:  { background: "var(--accent)", color: "#fff", borderColor: "var(--accent)" },
169	    solid:   { background: "var(--ink)", color: "var(--paper)", borderColor: "var(--ink)" },
170	    outline: { background: "var(--paper)", color: "var(--ink)", borderColor: "var(--line)" },
171	    ghost:   { background: "transparent", color: "var(--ink-2)", borderColor: "transparent" },
172	  };
173	  return (
174	    <button onClick={onClick} style={{ ...base, ...variants[variant], ...style }}>
175	      {icon && <Icon name={icon} size={size === "sm" ? 14 : 15} />}
176	      {children}
177	    </button>
178	  );
179	}
180	
181	/* ---------- avatar ---------- */
182	const AV_TONES = ["#3b3a7c", "#9a5b2e", "#2f6a52", "#7a3a6a", "#2e5c8a"];
183	function Avatar({ initials, size = 30, idx = 0, ring }) {
184	  return (
185	    <span style={{
186	      width: size, height: size, borderRadius: 99, flex: "none",
187	      background: AV_TONES[idx % AV_TONES.length], color: "#fff",
188	      display: "inline-flex", alignItems: "center", justifyContent: "center",
189	      fontSize: size * 0.36, fontWeight: 700, letterSpacing: ".02em",
190	      boxShadow: ring ? "0 0 0 2px var(--paper),0 0 0 3px var(--line)" : "none",
191	    }}>{initials}</span>
192	  );
193	}
194	
195	/* ---------- image placeholder (hero + thumbs) ---------- */
196	function ImgPlaceholder({ caption, big, style, onClick, active }) {
197	  return (
198	    <div onClick={onClick} style={{
199	      position: "relative", borderRadius: big ? 14 : 9, overflow: "hidden", cursor: onClick ? "pointer" : "default",
200	      background: "linear-gradient(135deg,#f0ede7,#e7e3db)",
201	      border: active ? "2px solid var(--brand)" : "1px solid var(--line)",
202	      boxShadow: active ? "0 0 0 3px var(--brand-50)" : "none",
203	      ...style,
204	    }}>
205	      <div style={{
206	        position: "absolute", inset: 0,
207	        backgroundImage: "repeating-linear-gradient(135deg,rgba(60,58,90,.05) 0 1px,transparent 1px 9px)",
208	      }} />
209	      <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: big ? 12 : 5, color: "var(--ink-4)" }}>
210	        <Icon name="image" size={big ? 40 : 18} sw={1.4} color="var(--ink-4)" />
211	        {big && <Mono style={{ fontSize: 11, letterSpacing: ".04em", color: "var(--ink-4)" }}>drop product photo</Mono>}
212	      </div>
213	      {caption && (
214	        <span style={{
215	          position: "absolute", left: big ? 12 : 6, bottom: big ? 12 : 6,
216	          fontFamily: "var(--mono)", fontSize: big ? 11 : 9, fontWeight: 500,
217	          color: "var(--ink-2)", background: "rgba(255,255,255,.82)", backdropFilter: "blur(3px)",
218	          padding: big ? "3px 9px" : "2px 6px", borderRadius: 6, letterSpacing: ".02em",
219	        }}>{caption}</span>
220	      )}
221	    </div>
222	  );
223	}
224	
225	/* hero + thumbnail strip, with interactive selection */
226	function Gallery({ images, layout = "below", heroH = 360 }) {
227	  const [sel, setSel] = useState(0);
228	  const hero = images[sel] || images[0];
229	  const strip = (
230	    <div style={{
231	      display: "flex", gap: 9, flexDirection: layout === "side" ? "column" : "row",
232	    }}>
233	      {images.map((im, i) => (
234	        <ImgPlaceholder key={im.id} caption={im.caption} onClick={() => setSel(i)} active={i === sel}
235	          style={{ width: layout === "side" ? 62 : 0, flex: layout === "side" ? "none" : "1 1 0", height: 62 }} />
236	      ))}
237	    </div>
238	  );
239	  if (layout === "side") {
240	    return (
241	      <div style={{ display: "flex", gap: 12 }}>
242	        {strip}
243	        <ImgPlaceholder big caption={hero.caption} style={{ flex: 1, height: heroH }} />
244	      </div>
245	    );
246	  }
247	  return (
248	    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
249	      <ImgPlaceholder big caption={hero.caption} style={{ width: "100%", height: heroH }} />
250	      {strip}
251	    </div>
252	  );
253	}
254	
255	/* ---------- tags ---------- */
256	function Tags({ tags, accentFirst }) {
257	  return (
258	    <div style={{ display: "flex", flexWrap: "wrap", gap: 7 }}>
259	      {tags.map((t, i) => (
260	        <span key={t} style={{
261	          display: "inline-flex", alignItems: "center", gap: 5, height: 24, padding: "0 10px",
262	          borderRadius: 7, fontSize: 12, fontWeight: 500,
263	          background: accentFirst && i === 0 ? "var(--brand-50)" : "var(--chip)",
264	          color: accentFirst && i === 0 ? "var(--brand-700)" : "var(--ink-2)",
265	          border: "1px solid " + (accentFirst && i === 0 ? "transparent" : "var(--line-2)"),
266	        }}>
267	          <span style={{ color: "var(--ink-4)", fontFamily: "var(--mono)", fontSize: 10 }}>#</span>{t}
268	        </span>
269	      ))}
270	    </div>
271	  );
272	}
273	
274	/* ---------- horizontal milestone timeline ---------- */
275	function Timeline({ items, compact }) {
276	  return (
277	    <div style={{ display: "flex", alignItems: "flex-start", width: "100%" }}>
278	      {items.map((m, i) => {
279	        const done = m.state === "done", cur = m.state === "current";
280	        const col = done ? "var(--brand)" : cur ? "var(--accent)" : "var(--line)";
281	        return (
282	          <div key={m.label} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", position: "relative", minWidth: 0 }}>
283	            {/* connector */}
284	            {i < items.length - 1 && (
285	              <span style={{
286	                position: "absolute", top: 7, left: "50%", width: "100%", height: 2,
287	                background: done ? "var(--brand)" : "var(--line)",
288	              }} />
289	            )}
290	            <span style={{
291	              width: 16, height: 16, borderRadius: 99, zIndex: 1, position: "relative",
292	              background: done ? "var(--brand)" : "var(--paper)",
293	              border: "2px solid " + col,
294	              display: "flex", alignItems: "center", justifyContent: "center",
295	              boxShadow: cur ? "0 0 0 4px var(--accent-50)" : "none",
296	            }}>
297	              {done && <Icon name="check" size={9} sw={2.6} color="#fff" />}
298	              {cur && <span style={{ width: 6, height: 6, borderRadius: 99, background: "var(--accent)" }} />}
299	            </span>
300	            <span style={{ marginTop: 9, fontSize: 11, fontWeight: 600, color: cur ? "var(--accent-700)" : done ? "var(--ink)" : "var(--ink-4)", textAlign: "center", lineHeight: 1.25, whiteSpace: "nowrap" }}>{m.label}</span>
301	            {!compact && <Mono style={{ marginTop: 2, fontSize: 10.5, color: "var(--ink-3)" }}>{m.date}</Mono>}
302	          </div>
303	        );
304	      })}
305	    </div>
306	  );
307	}
308	
309	/* ---------- main tab bar (Main / Licensing / Calendar) ---------- */
310	const TAB_META = { Main: { ic: "grid", tone: "indigo" }, Licensing: { ic: "layers", tone: "violet" }, Calendar: { ic: "cal", tone: "teal" } };
311	function TabBar({ tabs, active = 0, onChange, style }) {
312	  return (
313	    <div style={{ display: "flex", gap: 6, borderBottom: "1px solid var(--line)", ...style }}>
314	      {tabs.map((t, i) => {
315	        const m = TAB_META[t] || { ic: "grid", tone: "indigo" };
316	        const tn = ICON_TONES[m.tone];
317	        const act = i === active;
318	        return (
319	          <div key={t} onClick={() => onChange && onChange(i)} style={{
320	            display: "inline-flex", alignItems: "center", gap: 9, padding: "8px 14px 9px",
321	            fontSize: 13, fontWeight: act ? 700 : 500,
322	            color: act ? tn.fg : "var(--ink-3)",
323	            background: act ? tn.bg : "transparent",
324	            borderRadius: "8px 8px 0 0",
325	            borderBottom: "2px solid " + (act ? tn.fg : "transparent"), marginBottom: -1, cursor: "pointer",
326	          }}>
327	            <IconBadge name={m.ic} tone={m.tone} size={22} icon={13} style={act ? { boxShadow: "0 0 0 1.5px " + tn.fg + "33" } : { opacity: 0.85 }} />
328	            {t}
329	          </div>
330	        );
331	      })}
332	    </div>
333	  );
334	}
335	
336	/* ---------- segmented control (First / Second sub-tabs) ---------- */
337	function Segmented({ options, value, onChange, style }) {
338	  return (
339	    <div style={{ display: "inline-flex", background: "var(--chip)", borderRadius: 9, padding: 3, gap: 2, border: "1px solid var(--line-2)", ...style }}>
340	      {options.map((o, i) => (
341	        <button key={o} onClick={() => onChange(i)} style={{
342	          height: 28, padding: "0 16px", borderRadius: 6, border: "none", cursor: "pointer", fontFamily: "inherit",
343	          fontSize: 12.5, fontWeight: 600,
344	          background: i === value ? "var(--paper)" : "transparent",
345	          color: i === value ? "var(--ink)" : "var(--ink-3)",
346	          boxShadow: i === value ? "0 1px 2px rgba(28,27,34,.12)" : "none",
347	        }}>{o}</button>
348	      ))}
349	    </div>
350	  );
351	}
352	
353	/* ---------- key/value inline row (dense list style) ---------- */
354	function Row({ label, value, hint, mono, last, tone }) {
355	  const empty = !value || value === "-";
356	  const tc = tone ? (ICON_TONES[tone] || ICON_TONES.indigo) : null;
357	  return (
358	    <div style={{
359	      display: "grid", gridTemplateColumns: "minmax(120px,38%) 1fr", gap: 16, alignItems: "baseline",
360	      padding: tc ? "9px 0 9px 11px" : "9px 0", borderBottom: last ? "none" : "1px solid var(--line-2)",
361	      borderLeft: tc ? "2.5px solid " + tc.fg : "none",
362	    }}>
363	      <span style={{ fontSize: 12, fontWeight: 500, color: tc ? tc.fg : "var(--ink-3)", display: "inline-flex", gap: 6, alignItems: "baseline" }}>
364	        {label}{hint && (tc
365	          ? <Mono style={{ fontSize: 9, fontWeight: 600, background: tc.bg, color: tc.fg, padding: "1px 5px", borderRadius: 4 }}>{hint}</Mono>
366	          : <Mono style={{ fontSize: 9.5, color: "var(--ink-4)" }}>{hint}</Mono>)}
367	      </span>
368	      <span style={{ fontSize: 13, fontWeight: 500, color: empty ? "var(--ink-4)" : "var(--ink)", fontFamily: mono ? "var(--mono)" : "inherit", wordBreak: "break-word" }}>{empty ? "—" : value}</span>
369	    </div>
370	  );
371	}
372	
373	/* ---------- product team list ---------- */
374	function TeamList({ team, dense }) {
375	  return (
376	    <div style={{ display: "flex", flexDirection: "column", gap: dense ? 2 : 4 }}>
377	      {team.map((m, i) => (
378	        <div key={m.role} style={{ display: "flex", alignItems: "center", gap: 11, padding: dense ? "7px 0" : "8px 0", borderBottom: i < team.length - 1 ? "1px solid var(--line-2)" : "none" }}>
379	          <Avatar initials={m.initials} idx={i} size={30} />
380	          <div style={{ minWidth: 0, flex: 1 }}>
381	            <div style={{ fontSize: 12.5, fontWeight: 600, color: "var(--ink)", whiteSpace: "nowrap" }}>{m.name}</div>
382	            <div style={{ fontSize: 11, color: "var(--ink-3)", whiteSpace: "nowrap" }}>{m.role}</div>
383	          </div>
384	        </div>
385	      ))}
386	    </div>
387	  );
388	}
389	
390	/* ---------- comments ---------- */
391	function Comments({ comments }) {
392	  return (
393	    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
394	      {comments.map((c, i) => (
395	        <div key={i} style={{ display: "flex", gap: 10 }}>
396	          <Avatar initials={c.who.split(" ").map(w => w[0]).join("")} idx={i + 2} size={28} />
397	          <div style={{ minWidth: 0 }}>
398	            <div style={{ display: "flex", alignItems: "baseline", gap: 8 }}>
399	              <span style={{ fontSize: 12.5, fontWeight: 600, color: "var(--ink)", whiteSpace: "nowrap" }}>{c.who}</span>
400	              <Mono style={{ fontSize: 10.5, color: "var(--ink-4)" }}>{c.when}</Mono>
401	            </div>
402	            <p style={{ margin: "2px 0 0", fontSize: 12.5, lineHeight: 1.5, color: "var(--ink-2)" }}>{c.text}</p>
403	          </div>
404	        </div>
405	      ))}
406	    </div>
407	  );
408	}
409	
410	/* ---------- attachments / tech pack files ---------- */
411	function FileRow({ f, i, last }) {
412	  const tone = { PDF: "#bd5246", AI: "#c08a2a", IMG: "#3f8a5b" }[f.kind] || "var(--ink-3)";
413	  return (
414	    <div style={{ display: "flex", alignItems: "center", gap: 11, padding: "9px 0", borderBottom: last ? "none" : "1px solid var(--line-2)" }}>
415	      <span style={{ width: 30, height: 30, borderRadius: 7, flex: "none", background: "var(--chip)", color: tone, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "var(--mono)", fontSize: 9.5, fontWeight: 700 }}>{f.kind}</span>
416	      <div style={{ minWidth: 0, flex: 1 }}>
417	        <div style={{ fontSize: 12, fontWeight: 600, color: "var(--ink)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{f.name}</div>
418	        <Mono style={{ fontSize: 10.5, color: "var(--ink-3)" }}>{f.size}</Mono>
419	      </div>
420	      <span style={{ color: "var(--ink-3)" }}><Icon name="download" size={15} /></span>
421	    </div>
422	  );
423	}
424	
425	/* ---------- app chrome top bar ---------- */
426	function AppBar({ accent = "var(--brand)" }) {
427	  return (
428	    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 26px", height: 52, borderBottom: "1px solid var(--line)", background: "var(--paper)" }}>
429	      <div style={{ display: "flex", alignItems: "center", gap: 13 }}>
430	        <span style={{ width: 26, height: 26, borderRadius: 7, background: accent, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center" }}><Icon name="layers" size={16} color="#fff" /></span>
431	        <span style={{ fontSize: 14, fontWeight: 700, letterSpacing: "-.01em", color: "var(--ink)" }}>DesignFlow</span>
432	        <span style={{ width: 1, height: 18, background: "var(--line)", margin: "0 4px" }} />
433	        <nav style={{ display: "flex", alignItems: "center", gap: 7, fontSize: 12.5, color: "var(--ink-3)" }}>
434	          <span>Item Library</span><Icon name="chevR" size={13} color="var(--ink-4)" /><span style={{ color: "var(--ink-2)", fontWeight: 600 }}>EH-18635</span>
435	        </nav>
436	      </div>
437	      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
438	        <span style={{ color: "var(--ink-3)" }}><Icon name="search" size={17} /></span>
439	        <span style={{ color: "var(--ink-3)" }}><Icon name="bell" size={17} /></span>
440	        <Avatar initials="AR" idx={4} size={28} />
441	      </div>
442	    </div>
443	  );
444	}
445	
446	Object.assign(window, {
447	  Icon, Mono, Pill, Field, FieldGrid, Card, SectionLabel, Btn, Avatar, IconBadge, ICON_TONES,
448	  ImgPlaceholder, Gallery, Tags, Timeline, TabBar, Segmented, Row,
449	  TeamList, Comments, FileRow, AppBar,
450	});
451

