/* Shared UI atoms for the item-detail redesign.
   All styling inline (CSS-var driven) so the three variation files can
   reuse them. Exported to window at the bottom. */
const { useState } = React;

/* ---------- tiny line-icon set (functional UI glyphs only) ---------- */
function Icon({ name, size = 16, sw = 1.7, color = "currentColor", style }) {
  const p = {
    download:   <><path d="M12 4v10M8 12l4 4 4-4" /><path d="M5 19h14" /></>,
    upload:     <><path d="M12 20V10M8 12l4-4 4 4" /><path d="M5 5h14" /></>,
    edit:       <><path d="M14 5l5 5M4 20l1-4L16 5l3 3L8 19l-4 1z" /></>,
    plus:       <><path d="M12 5v14M5 12h14" /></>,
    check:      <><path d="M5 12l4.5 4.5L19 7" /></>,
    chevR:      <><path d="M9 5l7 7-7 7" /></>,
    chevL:      <><path d="M15 5l-7 7 7 7" /></>,
    chevD:      <><path d="M5 9l7 7 7-7" /></>,
    dot:        <circle cx="12" cy="12" r="4" fill={color} stroke="none" />,
    clock:      <><circle cx="12" cy="12" r="8" /><path d="M12 8v4l3 2" /></>,
    clip:       <><path d="M20 11l-8.5 8.5a4 4 0 01-6-6L13 5a2.6 2.6 0 014 3.5l-8 8a1.3 1.3 0 01-2-2l7.5-7.5" /></>,
    chat:       <><path d="M5 6h14v10H9l-4 4V6z" /></>,
    image:      <><rect x="4" y="5" width="16" height="14" rx="2" /><circle cx="9" cy="10" r="1.6" /><path d="M5 17l4.5-4 3 2.5L16 11l3 3.5" /></>,
    tag:        <><path d="M4 4h7l9 9-7 7-9-9V4z" /><circle cx="8" cy="8" r="1.4" /></>,
    ext:        <><path d="M14 5h5v5M19 5l-8 8M11 5H5v14h14v-6" /></>,
    user:       <><circle cx="12" cy="8" r="3.6" /><path d="M5 20c1.2-3.6 4-5 7-5s5.8 1.4 7 5" /></>,
    box:        <><path d="M4 8l8-4 8 4-8 4-8-4z" /><path d="M4 8v8l8 4 8-4V8M12 12v8" /></>,
    grid:       <><rect x="4" y="4" width="6" height="6" rx="1" /><rect x="14" y="4" width="6" height="6" rx="1" /><rect x="4" y="14" width="6" height="6" rx="1" /><rect x="14" y="14" width="6" height="6" rx="1" /></>,
    cal:        <><rect x="4" y="5" width="16" height="15" rx="2" /><path d="M4 9h16M9 3v4M15 3v4" /></>,
    layers:     <><path d="M12 4l8 4-8 4-8-4 8-4z" /><path d="M4 12l8 4 8-4M4 16l8 4 8-4" /></>,
    search:     <><circle cx="11" cy="11" r="6" /><path d="M20 20l-4-4" /></>,
    bell:       <><path d="M6 9a6 6 0 0112 0c0 5 2 6 2 6H4s2-1 2-6z" /><path d="M10 20a2 2 0 004 0" /></>,
    star:       <><path d="M12 4l2.4 5 5.6.6-4.2 3.8 1.2 5.6L12 16.2 7 19l1.2-5.6L4 9.6 9.6 9 12 4z" /></>,
    sparkle:    <><path d="M12 4l1.6 4.4L18 10l-4.4 1.6L12 16l-1.6-4.4L6 10l4.4-1.6L12 4z" /></>,
  }[name];
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
      stroke={color} strokeWidth={sw} strokeLinecap="round" strokeLinejoin="round"
      style={{ display: "block", flex: "none", ...style }}>{p}</svg>
  );
}

/* ---------- text helpers ---------- */
function Mono({ children, style }) {
  return <span style={{ fontFamily: "var(--mono)", fontFeatureSettings: '"tnum" 1', ...style }}>{children}</span>;
}

/* ---------- colored icon badge ---------- */
const ICON_TONES = {
  indigo: { bg: "#eceaf7", fg: "#403d8c" },
  violet: { bg: "#f1e7f8", fg: "#7d3ca3" },
  teal:   { bg: "#dff0ed", fg: "#1d7a6d" },
  green:  { bg: "#e6f1e9", fg: "#2e7a4d" },
  amber:  { bg: "#f8eed9", fg: "#9a6810" },
  clay:   { bg: "#f8eadf", fg: "#9c4f22" },
  blue:   { bg: "#e4edfc", fg: "#285aac" },
  rose:   { bg: "#fae6ec", fg: "#aa3957" },
};
function IconBadge({ name, tone = "indigo", size = 26, icon = 15, style }) {
  const t = ICON_TONES[tone] || ICON_TONES.indigo;
  return (
    <span style={{ width: size, height: size, borderRadius: 7, flex: "none", background: t.bg, color: t.fg, display: "flex", alignItems: "center", justifyContent: "center", ...style }}>
      <Icon name={name} size={icon} color={t.fg} />
    </span>
  );
}

/* ---------- status pill ---------- */
const PILL_TONES = {
  neutral: { bg: "var(--chip)",     fg: "var(--ink-2)",  dot: "var(--ink-3)" },
  brand:   { bg: "var(--brand-50)", fg: "var(--brand-700)", dot: "var(--brand)" },
  success: { bg: "#e8f1ea",         fg: "#2f6a45",       dot: "#3f8a5b" },
  warning: { bg: "#f7efe0",         fg: "#8a6312",       dot: "#c08a2a" },
  danger:  { bg: "#f7e7e4",         fg: "#9a3a30",       dot: "#bd5246" },
  accent:  { bg: "var(--accent-50)",fg: "var(--accent-700)", dot: "var(--accent)" },
};
function Pill({ tone = "neutral", dot = true, children, style }) {
  const t = PILL_TONES[tone] || PILL_TONES.neutral;
  return (
    <span style={{
      display: "inline-flex", alignItems: "center", gap: 6, height: 22,
      padding: "0 9px", borderRadius: 999, background: t.bg, color: t.fg,
      fontSize: 11.5, fontWeight: 600, letterSpacing: ".01em", whiteSpace: "nowrap", ...style,
    }}>
      {dot && <span style={{ width: 6, height: 6, borderRadius: 99, background: t.dot, flex: "none" }} />}
      {children}
    </span>
  );
}

/* ---------- read-only definition field ---------- */
function Field({ label, value, hint, mono, strong, accent, wide }) {
  const empty = value === undefined || value === null || value === "" || value === "-";
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 3, minWidth: 0, gridColumn: wide ? "1 / -1" : "auto" }}>
      <span style={{
        fontSize: 10.5, fontWeight: 600, letterSpacing: ".07em", textTransform: "uppercase",
        color: "var(--ink-3)", display: "inline-flex", alignItems: "center", gap: 5,
      }}>
        {label}
        {hint && <Mono style={{ fontSize: 9.5, color: "var(--ink-4)", fontWeight: 500, letterSpacing: 0 }}>{hint}</Mono>}
      </span>
      <span style={{
        fontSize: 13.5, lineHeight: 1.35,
        fontWeight: strong ? 600 : 500,
        fontFamily: mono ? "var(--mono)" : "inherit",
        color: empty ? "var(--ink-4)" : accent ? "var(--accent-700)" : "var(--ink)",
        wordBreak: "break-word",
      }}>{empty ? "—" : value}</span>
    </div>
  );
}

function FieldGrid({ cols = 3, children, gap = 22 }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: `repeat(${cols}, minmax(0,1fr))`, gap, rowGap: gap }}>
      {children}
    </div>
  );
}

/* ---------- card ---------- */
function Card({ title, kicker, action, children, pad = 18, style, bodyStyle, icon, tone = "indigo" }) {
  return (
    <section style={{
      background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 12,
      boxShadow: "0 1px 2px rgba(28,27,34,.04)", display: "flex", flexDirection: "column", minWidth: 0, ...style,
    }}>
      {(title || action) && (
        <header style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "11px 16px", borderBottom: "1px solid var(--line-2)", gap: 12,
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, minWidth: 0 }}>
            {icon && <IconBadge name={icon} tone={tone} size={28} icon={15} />}
            <div style={{ minWidth: 0 }}>
              {kicker && <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: ".09em", textTransform: "uppercase", color: ICON_TONES[tone].fg }}>{kicker}</div>}
              <h3 style={{ margin: 0, fontSize: 13.5, fontWeight: 600, color: "var(--ink)", letterSpacing: "-.01em", whiteSpace: "nowrap" }}>{title}</h3>
            </div>
          </div>
          {action}
        </header>
      )}
      <div style={{ padding: pad, ...bodyStyle }}>{children}</div>
    </section>
  );
}

function SectionLabel({ children, hint, icon, tone = "indigo" }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 13 }}>
      {icon && <IconBadge name={icon} tone={tone} size={22} icon={13} />}
      <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: ".08em", textTransform: "uppercase", color: "var(--ink-2)" }}>{children}</span>
      <span style={{ flex: 1, height: 1, background: "var(--line-2)" }} />
      {hint && <Mono style={{ fontSize: 10, color: "var(--ink-4)" }}>{hint}</Mono>}
    </div>
  );
}

/* ---------- buttons ---------- */
function Btn({ variant = "ghost", icon, children, onClick, size = "md", style }) {
  const h = size === "sm" ? 28 : 34;
  const base = {
    display: "inline-flex", alignItems: "center", gap: 7, height: h, padding: size === "sm" ? "0 11px" : "0 14px",
    borderRadius: 8, fontSize: 12.5, fontWeight: 600, cursor: "pointer", whiteSpace: "nowrap",
    border: "1px solid transparent", transition: "background .15s,border-color .15s,color .15s", fontFamily: "inherit",
  };
  const variants = {
    primary: { background: "var(--brand)", color: "#fff", borderColor: "var(--brand)" },
    accent:  { background: "var(--accent)", color: "#fff", borderColor: "var(--accent)" },
    solid:   { background: "var(--ink)", color: "var(--paper)", borderColor: "var(--ink)" },
    outline: { background: "var(--paper)", color: "var(--ink)", borderColor: "var(--line)" },
    ghost:   { background: "transparent", color: "var(--ink-2)", borderColor: "transparent" },
  };
  return (
    <button onClick={onClick} style={{ ...base, ...variants[variant], ...style }}>
      {icon && <Icon name={icon} size={size === "sm" ? 14 : 15} />}
      {children}
    </button>
  );
}

/* ---------- avatar ---------- */
const AV_TONES = ["#3b3a7c", "#9a5b2e", "#2f6a52", "#7a3a6a", "#2e5c8a"];
function Avatar({ initials, size = 30, idx = 0, ring }) {
  return (
    <span style={{
      width: size, height: size, borderRadius: 99, flex: "none",
      background: AV_TONES[idx % AV_TONES.length], color: "#fff",
      display: "inline-flex", alignItems: "center", justifyContent: "center",
      fontSize: size * 0.36, fontWeight: 700, letterSpacing: ".02em",
      boxShadow: ring ? "0 0 0 2px var(--paper),0 0 0 3px var(--line)" : "none",
    }}>{initials}</span>
  );
}

/* ---------- image placeholder (hero + thumbs) ---------- */
function ImgPlaceholder({ caption, big, style, onClick, active }) {
  return (
    <div onClick={onClick} style={{
      position: "relative", borderRadius: big ? 14 : 9, overflow: "hidden", cursor: onClick ? "pointer" : "default",
      background: "linear-gradient(135deg,#f0ede7,#e7e3db)",
      border: active ? "2px solid var(--brand)" : "1px solid var(--line)",
      boxShadow: active ? "0 0 0 3px var(--brand-50)" : "none",
      ...style,
    }}>
      <div style={{
        position: "absolute", inset: 0,
        backgroundImage: "repeating-linear-gradient(135deg,rgba(60,58,90,.05) 0 1px,transparent 1px 9px)",
      }} />
      <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: big ? 12 : 5, color: "var(--ink-4)" }}>
        <Icon name="image" size={big ? 40 : 18} sw={1.4} color="var(--ink-4)" />
        {big && <Mono style={{ fontSize: 11, letterSpacing: ".04em", color: "var(--ink-4)" }}>drop product photo</Mono>}
      </div>
      {caption && (
        <span style={{
          position: "absolute", left: big ? 12 : 6, bottom: big ? 12 : 6,
          fontFamily: "var(--mono)", fontSize: big ? 11 : 9, fontWeight: 500,
          color: "var(--ink-2)", background: "rgba(255,255,255,.82)", backdropFilter: "blur(3px)",
          padding: big ? "3px 9px" : "2px 6px", borderRadius: 6, letterSpacing: ".02em",
        }}>{caption}</span>
      )}
    </div>
  );
}

/* hero + thumbnail strip, with interactive selection */
function Gallery({ images, layout = "below", heroH = 360 }) {
  const [sel, setSel] = useState(0);
  const hero = images[sel] || images[0];
  const strip = (
    <div style={{
      display: "flex", gap: 9, flexDirection: layout === "side" ? "column" : "row",
    }}>
      {images.map((im, i) => (
        <ImgPlaceholder key={im.id} caption={im.caption} onClick={() => setSel(i)} active={i === sel}
          style={{ width: layout === "side" ? 62 : 0, flex: layout === "side" ? "none" : "1 1 0", height: 62 }} />
      ))}
    </div>
  );
  if (layout === "side") {
    return (
      <div style={{ display: "flex", gap: 12 }}>
        {strip}
        <ImgPlaceholder big caption={hero.caption} style={{ flex: 1, height: heroH }} />
      </div>
    );
  }
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
      <ImgPlaceholder big caption={hero.caption} style={{ width: "100%", height: heroH }} />
      {strip}
    </div>
  );
}

/* ---------- tags ---------- */
function Tags({ tags, accentFirst }) {
  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: 7 }}>
      {tags.map((t, i) => (
        <span key={t} style={{
          display: "inline-flex", alignItems: "center", gap: 5, height: 24, padding: "0 10px",
          borderRadius: 7, fontSize: 12, fontWeight: 500,
          background: accentFirst && i === 0 ? "var(--brand-50)" : "var(--chip)",
          color: accentFirst && i === 0 ? "var(--brand-700)" : "var(--ink-2)",
          border: "1px solid " + (accentFirst && i === 0 ? "transparent" : "var(--line-2)"),
        }}>
          <span style={{ color: "var(--ink-4)", fontFamily: "var(--mono)", fontSize: 10 }}>#</span>{t}
        </span>
      ))}
    </div>
  );
}

/* ---------- horizontal milestone timeline ---------- */
function Timeline({ items, compact }) {
  return (
    <div style={{ display: "flex", alignItems: "flex-start", width: "100%" }}>
      {items.map((m, i) => {
        const done = m.state === "done", cur = m.state === "current";
        const col = done ? "var(--brand)" : cur ? "var(--accent)" : "var(--line)";
        return (
          <div key={m.label} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", position: "relative", minWidth: 0 }}>
            {/* connector */}
            {i < items.length - 1 && (
              <span style={{
                position: "absolute", top: 7, left: "50%", width: "100%", height: 2,
                background: done ? "var(--brand)" : "var(--line)",
              }} />
            )}
            <span style={{
              width: 16, height: 16, borderRadius: 99, zIndex: 1, position: "relative",
              background: done ? "var(--brand)" : "var(--paper)",
              border: "2px solid " + col,
              display: "flex", alignItems: "center", justifyContent: "center",
              boxShadow: cur ? "0 0 0 4px var(--accent-50)" : "none",
            }}>
              {done && <Icon name="check" size={9} sw={2.6} color="#fff" />}
              {cur && <span style={{ width: 6, height: 6, borderRadius: 99, background: "var(--accent)" }} />}
            </span>
            <span style={{ marginTop: 9, fontSize: 11, fontWeight: 600, color: cur ? "var(--accent-700)" : done ? "var(--ink)" : "var(--ink-4)", textAlign: "center", lineHeight: 1.25, whiteSpace: "nowrap" }}>{m.label}</span>
            {!compact && <Mono style={{ marginTop: 2, fontSize: 10.5, color: "var(--ink-3)" }}>{m.date}</Mono>}
          </div>
        );
      })}
    </div>
  );
}

/* ---------- main tab bar (Main / Licensing / Calendar) ---------- */
const TAB_META = { Main: { ic: "grid", tone: "indigo" }, Licensing: { ic: "layers", tone: "violet" }, Calendar: { ic: "cal", tone: "teal" } };
function TabBar({ tabs, active = 0, onChange, style }) {
  return (
    <div style={{ display: "flex", gap: 6, borderBottom: "1px solid var(--line)", ...style }}>
      {tabs.map((t, i) => {
        const m = TAB_META[t] || { ic: "grid", tone: "indigo" };
        const tn = ICON_TONES[m.tone];
        const act = i === active;
        return (
          <div key={t} onClick={() => onChange && onChange(i)} style={{
            display: "inline-flex", alignItems: "center", gap: 9, padding: "8px 14px 9px",
            fontSize: 13, fontWeight: act ? 700 : 500,
            color: act ? tn.fg : "var(--ink-3)",
            background: act ? tn.bg : "transparent",
            borderRadius: "8px 8px 0 0",
            borderBottom: "2px solid " + (act ? tn.fg : "transparent"), marginBottom: -1, cursor: "pointer",
          }}>
            <IconBadge name={m.ic} tone={m.tone} size={22} icon={13} style={act ? { boxShadow: "0 0 0 1.5px " + tn.fg + "33" } : { opacity: 0.85 }} />
            {t}
          </div>
        );
      })}
    </div>
  );
}

/* ---------- segmented control (First / Second sub-tabs) ---------- */
function Segmented({ options, value, onChange, style }) {
  return (
    <div style={{ display: "inline-flex", background: "var(--chip)", borderRadius: 9, padding: 3, gap: 2, border: "1px solid var(--line-2)", ...style }}>
      {options.map((o, i) => (
        <button key={o} onClick={() => onChange(i)} style={{
          height: 28, padding: "0 16px", borderRadius: 6, border: "none", cursor: "pointer", fontFamily: "inherit",
          fontSize: 12.5, fontWeight: 600,
          background: i === value ? "var(--paper)" : "transparent",
          color: i === value ? "var(--ink)" : "var(--ink-3)",
          boxShadow: i === value ? "0 1px 2px rgba(28,27,34,.12)" : "none",
        }}>{o}</button>
      ))}
    </div>
  );
}

/* ---------- key/value inline row (dense list style) ---------- */
function Row({ label, value, hint, mono, last, tone }) {
  const empty = !value || value === "-";
  const tc = tone ? (ICON_TONES[tone] || ICON_TONES.indigo) : null;
  return (
    <div style={{
      display: "grid", gridTemplateColumns: "minmax(120px,38%) 1fr", gap: 16, alignItems: "baseline",
      padding: tc ? "9px 0 9px 11px" : "9px 0", borderBottom: last ? "none" : "1px solid var(--line-2)",
      borderLeft: tc ? "2.5px solid " + tc.fg : "none",
    }}>
      <span style={{ fontSize: 12, fontWeight: 500, color: tc ? tc.fg : "var(--ink-3)", display: "inline-flex", gap: 6, alignItems: "baseline" }}>
        {label}{hint && (tc
          ? <Mono style={{ fontSize: 9, fontWeight: 600, background: tc.bg, color: tc.fg, padding: "1px 5px", borderRadius: 4 }}>{hint}</Mono>
          : <Mono style={{ fontSize: 9.5, color: "var(--ink-4)" }}>{hint}</Mono>)}
      </span>
      <span style={{ fontSize: 13, fontWeight: 500, color: empty ? "var(--ink-4)" : "var(--ink)", fontFamily: mono ? "var(--mono)" : "inherit", wordBreak: "break-word" }}>{empty ? "—" : value}</span>
    </div>
  );
}

/* ---------- product team list ---------- */
function TeamList({ team, dense }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: dense ? 2 : 4 }}>
      {team.map((m, i) => (
        <div key={m.role} style={{ display: "flex", alignItems: "center", gap: 11, padding: dense ? "7px 0" : "8px 0", borderBottom: i < team.length - 1 ? "1px solid var(--line-2)" : "none" }}>
          <Avatar initials={m.initials} idx={i} size={30} />
          <div style={{ minWidth: 0, flex: 1 }}>
            <div style={{ fontSize: 12.5, fontWeight: 600, color: "var(--ink)", whiteSpace: "nowrap" }}>{m.name}</div>
            <div style={{ fontSize: 11, color: "var(--ink-3)", whiteSpace: "nowrap" }}>{m.role}</div>
          </div>
        </div>
      ))}
    </div>
  );
}

/* ---------- comments ---------- */
function Comments({ comments }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
      {comments.map((c, i) => (
        <div key={i} style={{ display: "flex", gap: 10 }}>
          <Avatar initials={c.who.split(" ").map(w => w[0]).join("")} idx={i + 2} size={28} />
          <div style={{ minWidth: 0 }}>
            <div style={{ display: "flex", alignItems: "baseline", gap: 8 }}>
              <span style={{ fontSize: 12.5, fontWeight: 600, color: "var(--ink)", whiteSpace: "nowrap" }}>{c.who}</span>
              <Mono style={{ fontSize: 10.5, color: "var(--ink-4)" }}>{c.when}</Mono>
            </div>
            <p style={{ margin: "2px 0 0", fontSize: 12.5, lineHeight: 1.5, color: "var(--ink-2)" }}>{c.text}</p>
          </div>
        </div>
      ))}
    </div>
  );
}

/* ---------- attachments / tech pack files ---------- */
function FileRow({ f, i, last }) {
  const tone = { PDF: "#bd5246", AI: "#c08a2a", IMG: "#3f8a5b" }[f.kind] || "var(--ink-3)";
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 11, padding: "9px 0", borderBottom: last ? "none" : "1px solid var(--line-2)" }}>
      <span style={{ width: 30, height: 30, borderRadius: 7, flex: "none", background: "var(--chip)", color: tone, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "var(--mono)", fontSize: 9.5, fontWeight: 700 }}>{f.kind}</span>
      <div style={{ minWidth: 0, flex: 1 }}>
        <div style={{ fontSize: 12, fontWeight: 600, color: "var(--ink)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{f.name}</div>
        <Mono style={{ fontSize: 10.5, color: "var(--ink-3)" }}>{f.size}</Mono>
      </div>
      <span style={{ color: "var(--ink-3)" }}><Icon name="download" size={15} /></span>
    </div>
  );
}

/* ---------- app chrome top bar ---------- */
function AppBar({ accent = "var(--brand)" }) {
  return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 26px", height: 52, borderBottom: "1px solid var(--line)", background: "var(--paper)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 13 }}>
        <span style={{ width: 26, height: 26, borderRadius: 7, background: accent, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center" }}><Icon name="layers" size={16} color="#fff" /></span>
        <span style={{ fontSize: 14, fontWeight: 700, letterSpacing: "-.01em", color: "var(--ink)" }}>DesignFlow</span>
        <span style={{ width: 1, height: 18, background: "var(--line)", margin: "0 4px" }} />
        <nav style={{ display: "flex", alignItems: "center", gap: 7, fontSize: 12.5, color: "var(--ink-3)" }}>
          <span>Item Library</span><Icon name="chevR" size={13} color="var(--ink-4)" /><span style={{ color: "var(--ink-2)", fontWeight: 600 }}>EH-18635</span>
        </nav>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <span style={{ color: "var(--ink-3)" }}><Icon name="search" size={17} /></span>
        <span style={{ color: "var(--ink-3)" }}><Icon name="bell" size={17} /></span>
        <Avatar initials="AR" idx={4} size={28} />
      </div>
    </div>
  );
}

Object.assign(window, {
  Icon, Mono, Pill, Field, FieldGrid, Card, SectionLabel, Btn, Avatar, IconBadge, ICON_TONES,
  ImgPlaceholder, Gallery, Tags, Timeline, TabBar, Segmented, Row,
  TeamList, Comments, FileRow, AppBar,
});

/* Variation A — Licensing & Calendar tab content.
   Same tightened system as the Main tab. Exported to window. */
const { useState: useTabState } = React;

/* slim full-width summary band (matches the Main timeline band) */
function SummaryBand({ icon, kicker, title, facts, right, tone = "indigo" }) {
  return (
    <div style={{ background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 12, boxShadow: "0 1px 2px rgba(28,27,34,.04)", display: "flex", alignItems: "center", gap: 24, padding: "12px 22px", flexWrap: "wrap" }}>
      <div style={{ flex: "none", display: "flex", alignItems: "center", gap: 10 }}>
        <IconBadge name={icon} tone={tone} size={30} icon={16} />
        <div>
          <div style={{ fontSize: 9.5, fontWeight: 700, letterSpacing: ".09em", textTransform: "uppercase", color: ICON_TONES[tone].fg }}>{kicker}</div>
          <div style={{ fontSize: 13, fontWeight: 600, lineHeight: 1.1 }}>{title}</div>
        </div>
      </div>
      <div style={{ width: 1, height: 30, background: "var(--line-2)", flex: "none" }} />
      <div style={{ flex: 1, display: "flex", flexWrap: "wrap", gap: 22, minWidth: 0 }}>
        {facts.map(([k, v]) => (
          <div key={k} style={{ display: "flex", flexDirection: "column", gap: 2 }}>
            <span style={{ fontSize: 9.5, fontWeight: 600, letterSpacing: ".06em", textTransform: "uppercase", color: "var(--ink-3)" }}>{k}</span>
            <span style={{ fontSize: 13, fontWeight: 600, color: "var(--ink)" }}>{v}</span>
          </div>
        ))}
      </div>
      {right && <div style={{ flex: "none" }}>{right}</div>}
    </div>
  );
}

/* progress meter */
function Progress({ value, w = 132 }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
      <div style={{ width: w, height: 7, borderRadius: 99, background: "var(--chip)", overflow: "hidden" }}>
        <div style={{ width: value + "%", height: "100%", borderRadius: 99, background: "var(--brand)" }} />
      </div>
      <Mono style={{ fontSize: 12, fontWeight: 600, color: "var(--ink-2)" }}>{value}%</Mono>
    </div>
  );
}

/* ---------- licensing stage tracker ---------- */
const STAGE_TONE = { done: "success", current: "accent", todo: "neutral" };
function StageTracker({ stages }) {
  return (
    <div style={{ display: "flex", alignItems: "stretch", gap: 0 }}>
      {stages.map((s, i) => {
        const done = s.state === "done", cur = s.state === "current";
        const col = done ? "var(--brand)" : cur ? "var(--accent)" : "var(--line)";
        return (
          <React.Fragment key={s.phase}>
            <div style={{ flex: 1, display: "flex", flexDirection: "column", border: "1px solid " + (cur ? "var(--accent)" : "var(--line)"), background: cur ? "var(--accent-50)" : "var(--paper)", borderRadius: 11, padding: "13px 14px", gap: 9, minWidth: 0 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <span style={{ width: 22, height: 22, borderRadius: 99, flex: "none", background: done ? "var(--brand)" : cur ? "var(--accent)" : "var(--chip)", color: done || cur ? "#fff" : "var(--ink-3)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11, fontWeight: 700 }}>
                  {done ? <Icon name="check" size={12} sw={2.6} color="#fff" /> : i + 1}
                </span>
                <span style={{ fontSize: 13, fontWeight: 600, color: "var(--ink)" }}>{s.phase}</span>
              </div>
              <Pill tone={STAGE_TONE[s.state]} style={{ alignSelf: "flex-start" }}>{s.status}</Pill>
              <div style={{ display: "flex", flexDirection: "column", gap: 5, marginTop: 2 }}>
                {s.steps.map(([label, date]) => (
                  <div key={label} style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between", gap: 8 }}>
                    <span style={{ fontSize: 11.5, color: "var(--ink-2)", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{label}</span>
                    <Mono style={{ fontSize: 11, color: date === "—" ? "var(--ink-4)" : "var(--ink-3)", flex: "none" }}>{date}</Mono>
                  </div>
                ))}
              </div>
            </div>
            {i < stages.length - 1 && (
              <div style={{ flex: "none", width: 26, alignSelf: "center", display: "flex", alignItems: "center", justifyContent: "center", color: done ? "var(--brand)" : "var(--ink-4)" }}>
                <Icon name="chevR" size={16} sw={2} />
              </div>
            )}
          </React.Fragment>
        );
      })}
    </div>
  );
}

/* ---------- feedback / approvals log table ---------- */
const FB_TONE = { Approved: "success", Revision: "warning", Submitted: "brand", Pending: "neutral" };
function FeedbackTable({ rows }) {
  const cols = "84px 104px 1fr 108px 150px";
  return (
    <div>
      <div style={{ display: "grid", gridTemplateColumns: cols, gap: 14, padding: "0 4px 9px", borderBottom: "1px solid var(--line)" }}>
        {["Date", "Stage", "POP Comment", "Status", "Assignee"].map(h => (
          <span key={h} style={{ fontSize: 10, fontWeight: 700, letterSpacing: ".06em", textTransform: "uppercase", color: "var(--ink-3)" }}>{h}</span>
        ))}
      </div>
      {rows.map((r, i) => (
        <div key={i} style={{ display: "grid", gridTemplateColumns: cols, gap: 14, padding: "11px 4px", borderBottom: i < rows.length - 1 ? "1px solid var(--line-2)" : "none", alignItems: "center" }}>
          <Mono style={{ fontSize: 11.5, color: "var(--ink-2)" }}>{r.date}</Mono>
          <span style={{ fontSize: 12, fontWeight: 600, color: "var(--ink)" }}>{r.stage}</span>
          <span style={{ fontSize: 12.5, color: "var(--ink-2)", lineHeight: 1.4 }}>{r.pop}</span>
          <Pill tone={FB_TONE[r.status]}>{r.status}</Pill>
          <div style={{ display: "flex", alignItems: "center", gap: 8, minWidth: 0 }}>
            <Avatar initials={r.who.split(" ").map(w => w[0]).join("")} idx={i} size={24} />
            <div style={{ minWidth: 0 }}>
              <div style={{ fontSize: 11.5, fontWeight: 600, color: "var(--ink)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{r.who}</div>
              <div style={{ fontSize: 10, color: "var(--ink-3)" }}>{r.from}</div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

/* ---------- Licensing tab ---------- */
function LicensingTab({ d }) {
  const L = d.licensing;
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <SummaryBand icon="layers" tone="violet" kicker="Licensing" title="Status"
        facts={[["Licensor", d.licensor], ["Property", d.property], ["Style Guide", d.styleGuide], ["Royalty", L.royalty], ["Contract #", L.contract]]}
        right={<div style={{ display: "flex", alignItems: "center", gap: 16 }}><Pill tone="success">{L.status}</Pill><Progress value={L.progress} /></div>} />

      <Card title="Licensing Timeline" icon="layers" tone="violet" kicker="Approval stages"
        action={<span style={{ fontSize: 11.5, color: "var(--ink-3)" }}>{L.approvalsRecv} approvals · {L.revisions} revisions</span>} pad={16}>
        <StageTracker stages={L.stages} />
      </Card>

      <div style={{ display: "grid", gridTemplateColumns: "1fr 332px", gap: 16, alignItems: "start" }}>
        <Card title="Feedback & Approvals" icon="chat" tone="green"
          action={<Btn variant="outline" size="sm" icon="plus">Add feedback</Btn>} pad={16}>
          <FeedbackTable rows={L.feedback} />
        </Card>
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <Card title="Royalty & Contract" icon="star" tone="amber" pad={16}>
            <FieldGrid cols={2} gap={14}>
              <Field label="Licensor" value={d.licensor} />
              <Field label="Royalty Rate" value={L.royalty} mono strong />
              <Field label="Contract #" value={L.contract} mono />
              <Field label="Brand Assurance" value={d.brandAssurance} />
              <Field label="Contract Ends" value={L.contractEnds} wide />
            </FieldGrid>
          </Card>
          <Card title="Submissions" icon="clip" tone="blue" pad={16}
            action={<Pill tone="neutral" dot={false}>{L.submissions.length}</Pill>}>
            {L.submissions.map((f, i) => (
              <div key={f.name} style={{ display: "flex", alignItems: "center", gap: 11, padding: "9px 0", borderBottom: i < L.submissions.length - 1 ? "1px solid var(--line-2)" : "none" }}>
                <span style={{ width: 30, height: 30, borderRadius: 7, flex: "none", background: "var(--chip)", color: "var(--ink-2)", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "var(--mono)", fontSize: 9, fontWeight: 700 }}>{f.kind}</span>
                <div style={{ minWidth: 0, flex: 1 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: "var(--ink)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{f.name}</div>
                  <Mono style={{ fontSize: 10.5, color: "var(--ink-3)" }}>{f.size} · {f.when}</Mono>
                </div>
                <span style={{ color: "var(--ink-3)" }}><Icon name="download" size={15} /></span>
              </div>
            ))}
          </Card>
          <Card title="Licensing Contacts" icon="user" tone="teal" pad={16}>
            <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
              {L.contacts.map((c, i) => (
                <div key={c.name} style={{ display: "flex", alignItems: "center", gap: 11, padding: "9px 0", borderBottom: i < L.contacts.length - 1 ? "1px solid var(--line-2)" : "none" }}>
                  <Avatar initials={c.name.split(" ").map(w => w[0]).join("")} idx={i + 3} size={32} />
                  <div style={{ minWidth: 0, flex: 1 }}>
                    <div style={{ fontSize: 12.5, fontWeight: 600, color: "var(--ink)" }}>{c.name}</div>
                    <div style={{ fontSize: 11, color: "var(--ink-3)" }}>{c.role} · {c.org}</div>
                    <Mono style={{ fontSize: 10.5, color: "var(--brand)" }}>{c.email}</Mono>
                  </div>
                </div>
              ))}
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
}

/* ---------- mini month calendar ---------- */
const CAL_DOT = { neutral: "var(--ink-3)", brand: "var(--brand)", accent: "var(--accent)", success: "#3f8a5b" };
const CAL_BG = { neutral: "var(--chip)", brand: "var(--brand-50)", accent: "var(--accent-50)", success: "#e8f1ea" };
const CAL_FG = { neutral: "var(--ink-2)", brand: "var(--brand-700)", accent: "var(--accent-700)", success: "#2f6a45" };
const MONTHS = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

function MiniCalendar({ events }) {
  // available months: Dec 2024 (0) .. Mar 2025 (3); default Feb 2025 (idx 2)
  const seq = [[2024, 11], [2025, 0], [2025, 1], [2025, 2]];
  const [mi, setMi] = useTabState(2);
  const [year, month] = seq[mi];
  const first = new Date(year, month, 1).getDay();
  const days = new Date(year, month + 1, 0).getDate();
  const evMap = {};
  events.forEach(e => {
    const dt = new Date(e.date + "T00:00:00");
    if (dt.getFullYear() === year && dt.getMonth() === month) evMap[dt.getDate()] = e;
  });
  const cells = [];
  for (let i = 0; i < first; i++) cells.push(null);
  for (let day = 1; day <= days; day++) cells.push(day);
  while (cells.length % 7) cells.push(null);

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14 }}>
        <h3 style={{ margin: 0, fontSize: 15, fontWeight: 700, letterSpacing: "-.01em" }}>{MONTHS[month]} <span style={{ color: "var(--ink-3)", fontWeight: 500 }}>{year}</span></h3>
        <div style={{ display: "flex", gap: 6 }}>
          <button onClick={() => setMi(Math.max(0, mi - 1))} disabled={mi === 0} style={{ width: 28, height: 28, borderRadius: 7, border: "1px solid var(--line)", background: "var(--paper)", color: mi === 0 ? "var(--ink-4)" : "var(--ink-2)", cursor: mi === 0 ? "default" : "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}><Icon name="chevL" size={15} /></button>
          <button onClick={() => setMi(Math.min(seq.length - 1, mi + 1))} disabled={mi === seq.length - 1} style={{ width: 28, height: 28, borderRadius: 7, border: "1px solid var(--line)", background: "var(--paper)", color: mi === seq.length - 1 ? "var(--ink-4)" : "var(--ink-2)", cursor: mi === seq.length - 1 ? "default" : "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}><Icon name="chevR" size={15} /></button>
        </div>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 6 }}>
        {["S", "M", "T", "W", "T", "F", "S"].map((w, i) => (
          <div key={i} style={{ textAlign: "center", fontSize: 10.5, fontWeight: 700, letterSpacing: ".04em", color: "var(--ink-4)", paddingBottom: 4 }}>{w}</div>
        ))}
        {cells.map((day, i) => {
          const ev = day && evMap[day];
          return (
            <div key={i} style={{ minHeight: 74, borderRadius: 8, border: "1px solid " + (ev ? "transparent" : "var(--line-2)"), background: ev ? CAL_BG[ev.tone] : day ? "var(--paper)" : "transparent", padding: "7px 8px", display: "flex", flexDirection: "column", gap: 5 }}>
              {day && <span style={{ fontSize: 11.5, fontWeight: ev ? 700 : 500, color: ev ? CAL_FG[ev.tone] : "var(--ink-3)" }}>{day}</span>}
              {ev && (
                <span style={{ fontSize: 9.5, fontWeight: 600, lineHeight: 1.2, color: CAL_FG[ev.tone] }}>
                  <span style={{ display: "inline-block", width: 5, height: 5, borderRadius: 99, background: CAL_DOT[ev.tone], marginRight: 4, verticalAlign: "middle" }} />{ev.label}
                </span>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ---------- Calendar tab ---------- */
function CalendarTab({ d }) {
  const evs = d.calendar.events;
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <SummaryBand icon="cal" tone="teal" kicker="Calendar" title="Key dates"
        facts={[["Created", d.created], ["Due", d.dueDate], ["On Shelf", d.onShelf], ["Lead Time", d.mfgLeadTime], ["Season", d.season]]}
        right={
          <div style={{ display: "flex", gap: 14 }}>
            {[["Done", "var(--brand)"], ["Due", "var(--accent)"], ["Ship", "#3f8a5b"]].map(([l, c]) => (
              <span key={l} style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 11.5, color: "var(--ink-3)" }}>
                <span style={{ width: 8, height: 8, borderRadius: 99, background: c }} />{l}
              </span>
            ))}
          </div>
        } />

      <div style={{ display: "grid", gridTemplateColumns: "1fr 360px", gap: 16, alignItems: "start" }}>
        <Card pad={18}>
          <MiniCalendar events={evs} />
        </Card>
        <Card title="All milestones" icon="clock" tone="indigo" pad={16}
          action={<span style={{ fontSize: 11.5, color: "var(--ink-3)" }}>{evs.length}</span>}>
          <div style={{ display: "flex", flexDirection: "column" }}>
            {evs.map((e, i) => {
              const dt = new Date(e.date + "T00:00:00");
              const mon = MONTHS[dt.getMonth()].slice(0, 3);
              const isDue = e.tone === "accent";
              return (
                <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, padding: "11px 0", borderBottom: i < evs.length - 1 ? "1px solid var(--line-2)" : "none" }}>
                  <div style={{ flex: "none", width: 46, textAlign: "center" }}>
                    <div style={{ fontSize: 9.5, fontWeight: 700, letterSpacing: ".05em", textTransform: "uppercase", color: "var(--ink-4)" }}>{mon}</div>
                    <Mono style={{ fontSize: 16, fontWeight: 600, color: isDue ? "var(--accent-700)" : "var(--ink)" }}>{dt.getDate()}</Mono>
                  </div>
                  <span style={{ width: 8, height: 8, borderRadius: 99, flex: "none", background: CAL_DOT[e.tone] }} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: "var(--ink)" }}>{e.label}</div>
                  </div>
                  <Pill tone={isDue ? "accent" : e.tone === "success" ? "success" : "neutral"} dot={false}>
                    {isDue ? "Due" : e.tone === "success" ? "Ship" : "Done"}
                  </Pill>
                </div>
              );
            })}
          </div>
        </Card>
      </div>
    </div>
  );
}

Object.assign(window, { SummaryBand, Progress, StageTracker, FeedbackTable, LicensingTab, MiniCalendar, CalendarTab });

