import { Component, ViewChild, AfterViewInit, ElementRef, ChangeDetectorRef } from '@angular/core';
import { ENTER } from '@angular/cdk/keycodes';
import { itemService } from '../../helpers/services/main.service'
import { AdminService } from '../../helpers/services/admin.service'
import { DateAdapter, MAT_DATE_FORMATS, MAT_DATE_LOCALE } from '@angular/material/core';
import { MomentDateAdapter, MAT_MOMENT_DATE_ADAPTER_OPTIONS } from '@angular/material-moment-adapter';
import { dateFormat } from '../../helpers/models/dateFormat.module'
import { UntypedFormControl } from '@angular/forms';
import { GalleryItem, Gallery } from 'ng-gallery';
import {
  ItemDetailService,
  ProductAssignmentRole,
  ProductAssignmentUpdate,
  ProductAssignmentUser
} from '../../helpers/services/item_detail.service'
import { imageEditorComponent } from '../itemLibrary/imageEditor/imageEditor.component';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { take } from 'rxjs/operators';
import { UploadFileComponent } from '../rfq/upload-file/upload-file.component';
import { ViewUploadedFilesDialogComponent } from '../itemLibrary/view-uploaded-files-dialog/view-uploaded-files-dialog.component';
import { ViewNotesDialogComponent } from '../itemLibrary/view-notes-dialog/view-notes-dialog.component';
import { MatAutocompleteSelectedEvent } from '@angular/material/autocomplete';
import { ActivatedRoute } from '@angular/router';
import { MatSelectChange } from '@angular/material/select';
import { FileUploadDialogComponent } from 'src/app/components/file-upload/file-upload-dialog.component';
import { firstValueFrom } from 'rxjs';
import { LoaderService } from '../../helpers/services/loader.service';
import { LicensingTrackingService } from '../../helpers/services/licensing_tracking.service';

@Component({
    selector: "app-itemDetail",
    templateUrl: "./itemDetail.component.html",
    styleUrls: ["./itemDetail.component.scss"],
    providers: [
        {
            provide: DateAdapter,
            useClass: MomentDateAdapter,
            deps: [MAT_DATE_LOCALE, MAT_MOMENT_DATE_ADAPTER_OPTIONS],
        },
        { provide: MAT_DATE_FORMATS, useValue: dateFormat },
    ],
    standalone: false
})
export class ItemDetailComponent implements AfterViewInit {
  isDesignOnly: boolean = false;
  techpacktDlBTN = false;
  powerpointDlBTN = false;
  editing: boolean = false;
  selectedProductType: any = { title: null };
  selectedProductSubType: any = { title: null };
  selectedProductSubSubType: any = { title: null };
  selectedPackageType: any = { title: null };
  selectedSize: any = { title: null };
  selectedLicensor: any = { title: null };
  selectedBigTheme: any = { title: null };
  selectedProperty: any = { title: null };
  selectedLittleTheme: any = { title: null };
  selectedDivisonCode: any = { title: null };
  selectedFormat: any = { title: null };
  selectedArtContent: any = { title: null };
  selectedDepth: any = { title: null };
  artistOptions: any = [];
  ageGroupOptions: any = [];
  forCustomerOptions: any = [];
  productTypeOptions: any[] = [];
  productSubTypeOptions: any[] = [];
  productSubSubTypeOptions: any[] = [];
  packageTypeOptions: any = [
    "Cardboard corners",
    "Traybox",
    "PVC bag with J-card",
    "Hanger with J-card and polybag",
    "Polybag with hangtag",
    "Packaging sticker",
    "Phone stand packaging",
    "Tablet stand packaging",
  ];

  sizeOptions: any = [];
  licensorOptions: any = [];
  bigThemeOptions: any = [];
  propertyOptions: any = [];
  littleThemeOptions: any = [];
  formatOptions: any = [];
  selectedArtist: any = { title: null };
  selectedAgeGroup: any = { title: null };
  selectedForCustomer: any = { title: null };
  artContentOptions: any = [];
  galleryId = "myLightbox";
  GalleryItems: GalleryItem[] = [];
  imageSliderObject: any[] = [];
  detailImages: any[] = [];
  styleGuideOptions: any[] = [];
  artTypeOptions: any[] = [];
  artSourceOptions: any[] = [];
  seasonptions: any[] = [];
  detailThumbs: any[] = [];
  asyncTabs: any = [];
  attachments: any = [];
  itemData: any = [];
  dates: any = [];
  selectedProductManager: any = {};
  selectedVendor: any = [];
  UDFElement: any = [];
  salesperOption: any = ["Adam"];
  UDFElementGroup: any = [];
  selectedActiveStatus: any = [];
  selectedDiscountStatus: any = [];
  selectedSeason: any = [];
  selectedArtType: any = [];
  selectedArtSource: any = [];
  selectedStyleGuide: any = [];
  productManagerOption = [];
  vendors: any[] = [];
  selectedSalesPerson: any = [];
  divisionOptions = [];
  yesNoOptions = [
    { title: "Yes", id: "Y" },
    { title: "No", id: "N" },
  ];
  mg: any = [];
  selected = false;
  itemDetailId: number;
  showCalendar: boolean = false;
  public files: any[] = [];
  isLoading = false;
  designRefNumber: number;
  divisions = { 1: "POP Lic", 2: "Spruce non-Lic", 7: "POP Lic", 8: "Spruce Lic", 9: "Spruce non-Lic" }
  depthOptions: any = [];
  // Tags (keywords)
  tags: string[] = [];
  readonly separatorKeysCodes: number[] = [ENTER];
  isStyleNumberPresent = false;
  requestStyleButtonLabel = "Request a style number";
  uploading: boolean = false;
  selectedTabIndex: number = 0;
  latestLicensingStatus: string = '';
  productAssignmentRoles: { role: ProductAssignmentRole; label: string }[] = [
    { role: 'creative_designer', label: 'Creative Designer' },
    { role: 'creative_director', label: 'Creative Director' },
    { role: 'technical_designer', label: 'Technical Designer' },
    { role: 'licensing_person', label: 'Licensing' },
    { role: 'salesperson', label: 'Salesperson' },
  ];
  assignmentUsers: ProductAssignmentUser[] = [];
  selectedProductAssignments: Partial<Record<ProductAssignmentRole, ProductAssignmentUser | null>> = {};
  savingProductAssignmentRole: ProductAssignmentRole | null = null;
  loadingProductAssignmentUsers = false;
  @ViewChild("myGallery") myGallery: ElementRef | undefined;
  @ViewChild("myThumbsContainer") myThumbsContainer: ElementRef | undefined;
  constructor(
    public dialog: MatDialog,
    private itemService: itemService,
    private adminService: AdminService,
    public gallery: Gallery,
    public ItemDetailService: ItemDetailService,
    private _snackBar: MatSnackBar,
    private cdr: ChangeDetectorRef,
    private loaderService: LoaderService,
    private route: ActivatedRoute,
    private licensingService: LicensingTrackingService
  ) { }

  async ngAfterViewInit() {
    this.cdr.detectChanges();
  }

  async onSelect(value) {
    return new Promise((res, rej) => {
      if (value != false) {
        this.selected = true;
      } else {
        this.selected = false;
      }
      res(this.selected);
    });
  }

  onSelectClosed() {
    this.selected = true;
  }

  async getDivisionCode(): Promise<number | undefined> {
    return new Promise((resolve) => {
      const hrefParts = document.location.href.split("/");
      const itemId =  hrefParts[hrefParts.length - 1].split('?')[0];

      // Start loader before item info request
      this.loaderService.increment();

      this.ItemDetailService.getItemInfo({ id: itemId }).subscribe({
        next: (item) => {
          this.itemData = item; // Store itemData for later use
          const currentItem = this.itemData[0];
          resolve(currentItem?.div_code_fk);
        },
        error: (error) => {
          // Turn off loader on error (comments won't load if item info fails)
          this.loaderService.decrement();
          resolve(undefined); // Fallback to undefined on error
        }
      });
    });
  }

  async ngOnInit() {
    this.uploading = true;
    let href = document.location.href.split("/");
    this.itemDetailId = href[href.length - 1].split('?')[0] as any;

    const divisionCode = await this.getDivisionCode();

    this.updateButtonState();
    this.loadProductAssignmentUsers();

    try {
      const res: any = await this.itemService.getSeasonCode().toPromise();
      this.seasonptions = res.data;
      this.seasonptions.sort((a, b) => (a.seasonDesc || '').localeCompare(b.seasonDesc || ''));
    } catch (err) {
      console.error('[ItemDetailComponent] getSeasonCode failed:', err);
    }

    await this.loadCustomerOptions()

    await this.itemService
      .getMerchGroup({ divisionCode })
      .subscribe(async (data: any) => {


        for (var i = 0; data.length > i; i++) {
          for (var j = 0; data[i].merchGroupHeaders.length > j; j++) {
            if (data[i].merchGroupHeaders[j].mgTypeDesc == "Material") {
              for (
                var k = 0;
                data[i].merchGroupHeaders[j].merchGroups.length > k;
                k++
              ) {
                if (data[i].merchGroupHeaders[j].merchGroups[k].is_active && data[i].merchGroupHeaders[j].merchGroups[k].divisionCode_id_fk === divisionCode ) {
                  this.productTypeOptions.push({
                    title: data[i].merchGroupHeaders[j].merchGroups[k].mg_desc,
                    id: data[i].merchGroupHeaders[j].merchGroups[k].mg_id,
                    mg_code: data[i].merchGroupHeaders[j].merchGroups[k].mg_code,
                    is_active: data[i].merchGroupHeaders[j].merchGroups[k].is_active,
                    parent_id: data[i].merchGroupHeaders[j].merchGroups[k].parent_id,
                    mgCode2: data[i].merchGroupHeaders[j].merchGroups[k].mgCode2,
                    created_year: new Date(data[i].merchGroupHeaders[j].merchGroups[k].createdTime).getFullYear()
                  });
