  customSort(field) {
    return field.sort((a, b) => 
      {
        const valA = a?.mgCode2 || a?.mg_code || a?.name;
        const valB = b?.mgCode2 || b?.mg_code || b?.name;
        return valA?.toLowerCase().localeCompare(valB?.toLowerCase());
      });
  }

  updateButtonState(): void {
    this.isStyleNumberPresent = !!this.itemData?.[0]?.item_num_id?.trim();
    this.requestStyleButtonLabel = this.isStyleNumberPresent
      ? "Update Item Details"
      : "Request a style number";
  }

  async getItemInfo() {
    if (!this.itemData || !this.itemData[0]) {
      return;
    }

    const currentItem = this.itemData[0];
    const isOldItem = currentItem.is_item_old === true;
    this.applyProductAssignmentsFromItem(currentItem.productUserAssignments || []);


    const isSpruceNonLic = currentItem.div_code_fk === 9;

    // Helper function to select based on item age
    const selectOption = (options, codeKey, idKey, applyYearCheck = false) => {
      return options.find((x) =>
        isOldItem
          ? x.mg_code === currentItem[codeKey] &&
          !x.is_active &&
          (!applyYearCheck || x.created_year !== 2025)
          : x.id === currentItem[idKey]
      );
    };

    // Merchgroup selections
    this.selectedProductType = selectOption(this.productTypeOptions, "udf_merchgroup01", "udf_merchgroup01_id", true);
    this.selectedProductSubType = selectOption(this.productSubTypeOptions, "udf_merchgroup02", "udf_merchgroup02_id", true);
    this.selectedProductSubSubType = selectOption(this.productSubSubTypeOptions, "udf_merchgroup03", "udf_merchgroup03_id", true);

    this.selectedSize = selectOption(this.sizeOptions, "udf_merchgroup04", "udf_merchgroup04_id");

    this.selectedLicensor = !isSpruceNonLic
      ? selectOption(this.licensorOptions, "udf_merchgroup05_fk", "udf_merchgroup05_fk_id")
      : null;

    this.selectedProperty = !isSpruceNonLic
      ? selectOption(this.propertyOptions, "udf_merchgroup06_fk", "udf_merchgroup06_fk_id")
      : null;

    this.selectedBigTheme = isSpruceNonLic
      ? selectOption(this.bigThemeOptions, "udf_merchgroup05_fk", "udf_merchgroup05_fk_id")
      : null;

    this.selectedLittleTheme = isSpruceNonLic
      ? selectOption(this.littleThemeOptions, "udf_merchgroup06_fk", "udf_merchgroup06_fk_id")
      : null;

    this.selectedArtType = isSpruceNonLic
      ? selectOption(this.artTypeOptions, "udf_merchgroup07_fk", "udf_merchgroup07_fk_id")
      : null;

    this.selectedStyleGuide = !isSpruceNonLic
      ? selectOption(this.styleGuideOptions, "udf_merchgroup07_fk", "udf_merchgroup07_fk_id")
      : null;

    this.selectedArtSource = selectOption(this.artSourceOptions, "udf_merchgroup08_fk", "udf_merchgroup08_fk_id");
    this.selectedArtist = selectOption(this.artistOptions, "udf_merchgroup09_fk", "udf_merchgroup09_fk_id");
    this.selectedAgeGroup = selectOption(this.ageGroupOptions, "udf_merchgroup10_fk", "udf_merchgroup10_fk_id");
    this.selectedForCustomer = selectOption(this.forCustomerOptions, "udf_merchgroup15_fk", "udf_merchgroup15_fk_id");


    // Other dropdown selections
    this.selectedDivisonCode = this.divisionOptions.find(x => x.comCode_id === currentItem.div_code_fk);
    this.selectedActiveStatus = this.yesNoOptions.find(x => x.id === currentItem.item_active_status);
    this.selectedDiscountStatus = this.yesNoOptions.find(x => x.id === currentItem.discont_status);
    this.selectedVendor = this.vendors.find(x => x.id === currentItem.vendor_code_fk);
    this.selectedSalesPerson = this.salesperOption.find(x => x === currentItem.salesper_code_fk);
    this.selectedPackageType = this.packageTypeOptions.find(x => x === currentItem.udf_freeform_06);
    this.selectedProductManager = this.productManagerOption.find(x => x.title === currentItem.productmanager);
    this.selectedSeason = this.seasonptions.find(x => x.seasonDesc === currentItem.season_code_fk);
    this.selectedDepth = this.depthOptions.find(x => x.title === currentItem.item_depth_size);

    // Design ref
    this.designRefNumber = currentItem.dsn_ref_num;
    this.isDesignOnly = !!this.designRefNumber;

    // Fetch additional MG data
    this.itemService.getMG({
      division_name: currentItem.compan_code_fk,
      company_name: currentItem.div_code_fk,
    }).subscribe((data) => {
      this.mg = data;
    });

    // Tags
    const tagsCsv = currentItem.tags || '';
    this.tags = tagsCsv ? tagsCsv.split(',').map((t: string) => t.trim()).filter((t: string) => !!t) : [];

    // Date fields
    const dateFields = [
      currentItem.udf_date01,
      currentItem.udf_date02,
      currentItem.udf_date03,
      currentItem.udf_date05,
      currentItem.udf_date06,
      currentItem.created_time_date,
      currentItem.due_date,
    ];
    this.dates = dateFields.map(date => new UntypedFormControl(date));

    // Fetch latest licensing status from licensingStatus table
    this.ItemDetailService.GetLicensingStatus(this.itemDetailId).subscribe({
      next: (statuses: any[]) => {
        if (statuses && statuses.length > 0) {
          this.latestLicensingStatus = statuses[statuses.length - 1].status || '';
        }
      },
      error: (err) => console.error('[ItemDetailComponent] GetLicensingStatus failed:', err)
    });

    // Assign extra fields
    currentItem.royalty_code_fk = this.itemData[0].royalty_code_fk;
    currentItem.mod_user_fk = this.itemData[0].mod_user_fk;
  }

  loadProductAssignmentUsers(): void {
    this.loadingProductAssignmentUsers = true;
    this.licensingService.getAllUsers({}).subscribe({
      next: (users: ProductAssignmentUser[]) => {
        this.assignmentUsers = (users || []).slice().sort((a, b) =>
          this.getUserDisplayName(a).localeCompare(this.getUserDisplayName(b))
        );
        this.loadingProductAssignmentUsers = false;
      },
      error: (err) => {
        console.error('[ItemDetailComponent] getAllUsers failed:', err);
        this.assignmentUsers = [];
        this.loadingProductAssignmentUsers = false;
      }
    });
  }

  applyProductAssignmentsFromItem(assignments: any[]): void {
    const nextAssignments: Partial<Record<ProductAssignmentRole, ProductAssignmentUser | null>> = {};
    for (const { role } of this.productAssignmentRoles) {
      const assignment = assignments.find(a => a.role === role);
      nextAssignments[role] = assignment?.user || null;
    }
    this.selectedProductAssignments = nextAssignments;
  }

  getUserDisplayName(user: ProductAssignmentUser | null | undefined): string {
    if (!user) return '';
    return `${user.name || ''} ${user.lastname || ''}`.trim() || user.email || `User ${user.id}`;
  }

  compareAssignmentUsers = (
    left: ProductAssignmentUser | null,
    right: ProductAssignmentUser | null
  ): boolean => {
    return (left?.id ?? null) === (right?.id ?? null);
  };

  async onProductAssignmentChange(role: ProductAssignmentRole, event: MatSelectChange): Promise<void> {
    const selectedUser = event.value as ProductAssignmentUser | null;
    const payload: ProductAssignmentUpdate[] = [{
      role,
      userId: selectedUser?.id ?? null,
    }];

    this.savingProductAssignmentRole = role;
    try {
      const response = await firstValueFrom(
        this.ItemDetailService.setProductAssignments(this.itemDetailId, payload)
      );
      this.itemData[0].productUserAssignments = response.data;
      this.applyProductAssignmentsFromItem(response.data);
      this._snackBar.open('Product assignment updated.', 'close', { duration: 2000 });
    } catch (err) {
      console.error('[ItemDetailComponent] setProductAssignments failed:', err);
      this._snackBar.open('Could not update product assignment.', 'close', { duration: 3000 });
    } finally {
      this.savingProductAssignmentRole = null;
    }
  }

