  }

  async onStyleNumber() {
    this.ItemDetailService.reqStyeNumber(this.itemData[0]).subscribe(
      async (res: any) => {
        if (res.statusCode === 200) {
          localStorage.removeItem('itemLibrary');

          // Check if item_num_id exists and is not null/empty
          if (this.itemData[0].item_num_id) {
            this._snackBar.open(
              `Item details updated in coldlion for the style number: ${res.itemNo}.`,
              "close"
            );
          } else {
            this._snackBar.open(
              `Request was sent successfully, style number is: ${res.itemNo}.`,
              "close"
            );
          }

          try {
            const data: any = await window["ItemLibraryService"].getAllitems().toPromise();
            window['params'].api.setRowData(data);
            data.push({ expirationTime: Date.now() });
            localStorage.setItem('itemLibrary', JSON.stringify(data));
          } catch (err) {
            console.error('[ItemDetailComponent] ItemLibraryService.getAllitems failed:', err);
          }
        } else {
          this._snackBar.open(`Something went wrong.`, "close");
        }
      }
    );

  }

  async getItemDepth() {
    try {
      const data: any = await this.itemService.getItemDepth().toPromise();
      this.depthOptions = data.map(item => ({
        title: item.itemDepth_title,
        id: item.itemDepth_id,
        code: item.itemDepth_code
      }));
      this.depthOptions.sort((a, b) => a.title.localeCompare(b.title));
    } catch (err) {
      console.error('[ItemDetailComponent] getItemDepth failed:', err);
    }
  }



  onCommentsLoaded(isLoaded: boolean) {
    if (isLoaded) {
      this.uploading = false;
      // Turn off loader after comments are loaded
      this.loaderService.decrement();
    }
  }
}

