// ----- Direction A redesign helpers -----

/** True when the current item belongs to the Spruce non-Lic division (theme/art-type variant). */
get isSpruceNonLic(): boolean {
  return this.itemData?.[0]?.div_code_fk === 9;
}

/** Two-letter initials from a person's display name. */
initials(name: string | null | undefined): string {
  if (!name) return '?';
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (!parts.length) return '?';
  return (parts[0][0] + (parts.length > 1 ? parts[parts.length - 1][0] : '')).toUpperCase();
}

/** Product team rows for the read-only roster (role + assigned user, if any). */
get teamMembers(): { role: ProductAssignmentRole; label: string; name: string; initials: string }[] {
  return this.productAssignmentRoles.map((r) => {
    const user = this.selectedProductAssignments[r.role] || null;
    const name = this.getUserDisplayName(user);
    return { role: r.role, label: r.label, name, initials: this.initials(name) };
  });
}

/**
 * Production milestone timeline derived from the item's real date fields.
 * Each milestone is `done` (date in the past), `current` (next upcoming /
 * first without a past date) or `todo`.
 */
get timelineItems(): { label: string; date: any; state: 'done' | 'current' | 'todo' }[] {
  const ci = this.itemData?.[0];
  if (!ci) return [];
  const points = [
    { label: 'Created', date: ci.created_time_date },
    { label: 'Test Report', date: ci.udf_date02 },
    { label: 'Photography', date: ci.udf_date03 },
    { label: 'Due', date: ci.due_date },
    { label: 'On Shelf', date: ci.udf_date01 },
  ];
  const now = Date.now();
  let currentAssigned = false;
  return points.map((p) => {
    const t = p.date ? new Date(p.date).getTime() : NaN;
    let state: 'done' | 'current' | 'todo';
    if (!isNaN(t) && t < now) {
      state = 'done';
    } else if (!currentAssigned) {
      state = 'current';
      currentAssigned = true;
    } else {
      state = 'todo';
    }
    return { label: p.label, date: p.date, state };
  });
}

