import { describe, expect, test } from '@jest/globals';
import { readFileSync } from 'fs';
import { join } from 'path';

const TEMPLATE_PATH = join(__dirname, 'itemDetail.component.html');

/**
 * Read-only attributes now live in the redesigned "Item Attributes" card,
 * driven by the `attrSet` segmented control (0 = First, 1 = Second, 2 = Third)
 * instead of nested <mat-tab>s. Extract one attrSet block by its guard.
 */
function extractReadOnlyAttrSet(index: 0 | 1 | 2): string {
  const source = readFileSync(TEMPLATE_PATH, 'utf8');
  const start = source.indexOf(`@if (attrSet === ${index}) {`);
  expect(start).toBeGreaterThan(-1);
  const next = source.indexOf('@if (attrSet === ', start + 1);
  return source.slice(start, next > -1 ? next : undefined);
}

/** The editable First form is still a <mat-tab label="First"> (edit mode). */
function extractEditTab(label: 'First' | 'Second'): string {
  const source = readFileSync(TEMPLATE_PATH, 'utf8');
  const tabStart = source.indexOf(`<mat-tab label="${label}">`);
  expect(tabStart).toBeGreaterThan(-1);
  const nextTabStart = source.indexOf('<mat-tab label=', tabStart + 1);
  return source.slice(tabStart, nextTabStart > -1 ? nextTabStart : undefined);
}

describe('itemDetail For Cust placement', () => {
  test('shows For Customer directly below Cust Designed in the read-only First attribute set', () => {
    const first = extractReadOnlyAttrSet(0);
    const custDesignedIndex = first.indexOf('df-field-label">Cust Designed');
    const forCustIndex = first.indexOf('df-field-label">For Customer');

    expect(custDesignedIndex).toBeGreaterThan(-1);
    expect(forCustIndex).toBeGreaterThan(custDesignedIndex);
  });

  test('shows For Cust directly below Cust Designed in the edit First tab', () => {
    const firstTab = extractEditTab('First');
    const custDesignedIndex = firstTab.indexOf('<mat-label>Cust Designed</mat-label>');
    const forCustIndex = firstTab.indexOf('<mat-label> For Cust</mat-label>');

    expect(custDesignedIndex).toBeGreaterThan(-1);
    expect(forCustIndex).toBeGreaterThan(custDesignedIndex);
  });

  test('does not show For Cust in the read-only Second attribute set', () => {
    const second = extractReadOnlyAttrSet(1);

    expect(second).not.toContain('df-field-label">For Customer');
    expect(second).not.toContain('df-field-label">Cust Designed');
  });

  test('does not show For Cust on the edit Second tab', () => {
    const secondTab = extractEditTab('Second');

    expect(secondTab).not.toContain('<mat-label> For Cust</mat-label>');
  });
});

