input.new_string:
/* gallery / image card: compact the hero so it fits the narrow left column */
.df-redesign .df-gallery-card .df-card-body { display: flex; flex-direction: column; }
.df-redesign .df-gallery-card image-upload { display: block; width: 100%; }
.df-redesign .df-gallery-card ::ng-deep #image-gallery,
.df-redesign .df-gallery-card ::ng-deep gallery {
  display: block;
  width: 100%;
  height: 250px;
  border-radius: 10px;
  overflow: hidden;
}
/* keep the upload/thumbnail controls under the hero from ballooning */
.df-redesign .df-gallery-card ::ng-deep .bottom-strip { margin-top: 10px; }
.df-redesign .df-gallery-card ::ng-deep .drag-and-drop { max-width: 60px; height: auto; }

